const scanId = $('Run Exploratory Test').first().json.scanId;
// ↑ yahan apne scan result node ka naam lagana hai
// jahan se scanId aa raha hai.

const files = $json.files;

return files.map(file => ({
  json: {
    scanId,
    fileName: file,
    screenshotUrl:
      `https://n8n1-qa-browser-agent.hf.space/screenshots/${scanId}/${file}`
  }
}));

const report = $('Run Exploratory Test').first().json.reportPayload;

const pages = report.pages || [];

// ---------- Health Score ----------
let score = 100;

score -= (report.scanSummary?.critical || 0) * 25;
score -= (report.scanSummary?.high || 0) * 10;
score -= (report.scanSummary?.medium || 0) * 1;
score -= (report.scanSummary?.low || 0) * 0.5;

score = Math.max(0, Math.round(score));

// ---------- Performance ----------
const totalLoadTime = pages.reduce(
  (sum, p) => sum + (p.loadTimeMs || 0),
  0
);

const averageLoadTime =
  pages.length > 0
    ? Math.round(totalLoadTime / pages.length)
    : 0;

const slowPages = pages
  .filter(p => p.performanceIssue)
  .map(p => ({
    url: p.url,
    loadTimeMs: p.loadTimeMs
  }));

// ---------- Accessibility ----------
const accessibilityIssueCount = pages.reduce(
  (sum, p) =>
    sum + (p.accessibilityIssues?.length || 0),
  0
);

const imagesWithoutAltCount = pages.reduce(
  (sum, p) =>
    sum + (p.imagesWithoutAlt?.length || 0),
  0
);

// ---------- Forms ----------
const brokenFormsCount = pages.reduce(
  (sum, p) =>
    sum + (p.brokenForms?.length || 0),
  0
);

// ---------- Most Affected Pages ----------
const topAffectedPages = [...pages]
  .map(page => ({
    url: page.url,
    severity: page.overallSeverity,
    issuesCount:
      (page.severitySummary?.critical || 0) +
      (page.severitySummary?.high || 0) +
      (page.severitySummary?.medium || 0) +
      (page.severitySummary?.low || 0)
  }))
  .sort((a, b) => b.issuesCount - a.issuesCount)
  .slice(0, 5);

// ---------- AI Payload ----------
return [{
  json: {
    websiteUrl: report.websiteUrl,
    scanDate: report.scanDate,

    healthScore: score,

    scanSummary: report.scanSummary,

    averageLoadTime,
    slowPages,

    accessibilityIssueCount,
    imagesWithoutAltCount,
    brokenFormsCount,

    topAffectedPages,

    pages: pages.map(page => ({
      url: page.url,
      severity: page.overallSeverity,

      issuesCount:
        (page.severitySummary?.critical || 0) +
        (page.severitySummary?.high || 0) +
        (page.severitySummary?.medium || 0) +
        (page.severitySummary?.low || 0),

      findings:
        page.findings
          ?.slice(0, 5)
          .map(f => f.type) || []
    }))
  }
}];

const output = {
  json: { ...$input.first().json },
  binary: {}
};

for (const item of $input.all()) {
  if (!item.binary) continue;

  for (const key of Object.keys(item.binary)) {
    const file = item.binary[key];

    const fileName =
      file.fileName?.replace(/[^a-zA-Z0-9_.-]/g, '_') ||
      `file_${Date.now()}`;

    output.binary[fileName] = file;
  }
}

return [output];

const url = $input.first().json['Enter the website url '].trim();

if (!/^https?:\/\/.+/i.test(url)) {
  throw new Error('Please enter a valid URL starting with http:// or https://');
}

return {
  url
};

const scanId = Date.now().toString();

return {
  scanId,
  url: $input.item.json.url,
  status: 'PENDING',
  createdAt: new Date().toISOString()
};

