const rawData = items[0].json;

// Safe Data Normalization: Extracting data properly from the nested JSON
const data = {
    websiteUrl: rawData.url || (rawData.reportPayload && rawData.reportPayload.websiteUrl) || "Unknown URL",
    scanDate: (rawData.reportPayload && rawData.reportPayload.scanDate) || new Date().toISOString(),
    scanSummary: rawData.scanSummary || (rawData.reportPayload && rawData.reportPayload.scanSummary) || { totalPages: 0, critical: 0, high: 0, medium: 0, low: 0 },
    pages: (rawData.reportPayload && rawData.reportPayload.pages) || rawData.inventory || []
};

// Safe stringify for injecting data into the client-side script
const reportDataJSON = JSON.stringify(data).replace(/</g, '\\u003c');

const html = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Advanced UI Scan Report - ${data.websiteUrl}</title>
    <script src="https://cdn.tailwindcss.com"></script>
    <script src="https://cdn.jsdelivr.net/npm/chart.js"></script>
    <link href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.0.0/css/all.min.css" rel="stylesheet">
    <style>
        .details-row { display: none; }
        .details-row.active { display: table-row; }
        .badge { padding: 4px 8px; border-radius: 12px; font-weight: bold; font-size: 0.75rem; color: white; }
        .bg-critical { background-color: #ef4444; }
        .bg-high { background-color: #f97316; }
        .bg-medium { background-color: #eab308; }
        .bg-low { background-color: #3b82f6; }
    </style>
</head>
<body class="bg-slate-50 text-slate-800 font-sans antialiased">

    <nav class="bg-indigo-600 text-white p-4 shadow-lg flex justify-between items-center">
        <div>
            <h1 class="text-2xl font-bold"><i class="fa-solid fa-shield-halved mr-2"></i> Security & Quality Deep Audit</h1>
            <a href="${data.websiteUrl}" target="_blank" class="text-indigo-200 hover:text-white underline text-sm"><i class="fa-solid fa-link mr-1"></i>${data.websiteUrl}</a>
        </div>
        <div class="text-right">
            <p class="text-sm text-indigo-200">Scan Date</p>
            <p class="font-bold">${new Date(data.scanDate).toLocaleString()}</p>
        </div>
    </nav>

    <div class="max-w-7xl mx-auto p-6">

        <div class="grid grid-cols-1 md:grid-cols-5 gap-4 mb-8">
            <div id="card-all" onclick="filterBySeverity('all')" class="bg-white p-4 rounded-xl shadow-sm border-l-4 border-indigo-500 cursor-pointer hover:shadow-md transition-all ring-2 ring-indigo-600 bg-indigo-50/50">
                <h3 class="text-gray-500 text-xs font-semibold uppercase">Total Pages Scanned</h3>
                <p class="text-3xl font-bold mt-1 text-indigo-600">${data.scanSummary.totalPages || data.pages.length}</p>
                <span class="text-xs text-slate-400">Click to clear filters</span>
            </div>
            <div id="card-critical" onclick="filterBySeverity('critical')" class="bg-white p-4 rounded-xl shadow-sm border-l-4 border-red-500 cursor-pointer hover:shadow-md transition-all">
                <h3 class="text-gray-500 text-xs font-semibold uppercase">Critical Issues</h3>
                <p class="text-3xl font-bold mt-1 text-red-500">${data.scanSummary.critical || 0}</p>
                <span class="text-xs text-slate-400">Click to filter</span>
            </div>
            <div id="card-high" onclick="filterBySeverity('high')" class="bg-white p-4 rounded-xl shadow-sm border-l-4 border-orange-500 cursor-pointer hover:shadow-md transition-all">
                <h3 class="text-gray-500 text-xs font-semibold uppercase">High Issues</h3>
                <p class="text-3xl font-bold mt-1 text-orange-500">${data.scanSummary.high || 0}</p>
                <span class="text-xs text-slate-400">Click to filter</span>
            </div>
            <div id="card-medium" onclick="filterBySeverity('medium')" class="bg-white p-4 rounded-xl shadow-sm border-l-4 border-yellow-500 cursor-pointer hover:shadow-md transition-all">
                <h3 class="text-gray-500 text-xs font-semibold uppercase">Medium Issues</h3>
                <p class="text-3xl font-bold mt-1 text-yellow-600">${data.scanSummary.medium || 0}</p>
                <span class="text-xs text-slate-400">Click to filter</span>
            </div>
            <div id="card-low" onclick="filterBySeverity('low')" class="bg-white p-4 rounded-xl shadow-sm border-l-4 border-blue-500 cursor-pointer hover:shadow-md transition-all">
                <h3 class="text-gray-500 text-xs font-semibold uppercase">Low Issues</h3>
                <p class="text-3xl font-bold mt-1 text-blue-500">${data.scanSummary.low || 0}</p>
                <span class="text-xs text-slate-400">Click to filter</span>
            </div>
        </div>

        <div class="grid grid-cols-1 md:grid-cols-2 gap-8 mb-8">
            <div class="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h2 class="text-lg font-bold mb-4 text-center"><i class="fa-solid fa-chart-pie mr-2"></i>Severity Distribution</h2>
                <div class="relative h-64 w-full flex justify-center">
                    <canvas id="severityPieChart"></canvas>
                </div>
            </div>
            <div class="bg-white p-6 rounded-xl shadow-sm border border-gray-100">
                <h2 class="text-lg font-bold mb-4 text-center"><i class="fa-solid fa-chart-bar mr-2"></i>Issues Per Page (Top 10)</h2>
                <div class="relative h-64 w-full">
                    <canvas id="issuesBarChart"></canvas>
                </div>
            </div>
        </div>

        <div class="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden">
            <div class="p-4 bg-gray-50 border-b border-gray-200 flex flex-col sm:flex-row justify-between items-start sm:items-center gap-4">
                <h2 class="text-xl font-bold"><i class="fa-solid fa-list mr-2"></i>Detailed Page Analysis <span id="activeFilterBadge" class="hidden text-xs bg-indigo-100 text-indigo-800 ml-2 px-2.5 py-0.5 rounded-full font-semibold"></span></h2>

                <div class="relative w-full sm:w-72">
                    <span class="absolute inset-y-0 left-0 flex items-center pl-3 pointer-events-none text-slate-400">
                        <i class="fa-solid fa-magnifying-glass"></i>
                    </span>
                    <input type="text" id="tableSearch" onkeyup="handleSearch()" class="w-full pl-9 pr-4 py-2 border border-slate-200 rounded-lg text-sm focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 shadow-sm" placeholder="Search pages or URLs...">
                </div>
            </div>

            <div class="overflow-x-auto">
                <table class="w-full text-left border-collapse">
                    <thead>
                        <tr class="bg-gray-100 text-gray-600 uppercase text-sm select-none">
                            <th class="p-4 font-semibold cursor-pointer hover:bg-gray-200 transition-colors" onclick="sortTable(0, 'text')">Page Title <i class="fa-solid fa-sort text-xs ml-1 text-slate-400"></i></th>
                            <th class="p-4 font-semibold cursor-pointer hover:bg-gray-200 transition-colors" onclick="sortTable(1, 'number')">Load Time <i class="fa-solid fa-sort text-xs ml-1 text-slate-400"></i></th>
                            <th class="p-4 font-semibold cursor-pointer hover:bg-gray-200 transition-colors" onclick="sortTable(2, 'number')">Issues <i class="fa-solid fa-sort text-xs ml-1 text-slate-400"></i></th>
                            <th class="p-4 font-semibold cursor-pointer hover:bg-gray-200 transition-colors" onclick="sortTable(3, 'severity')">Severity <i class="fa-solid fa-sort text-xs ml-1 text-slate-400"></i></th>
                            <th class="p-4 font-semibold text-center">Action</th>
                        </tr>
                    </thead>
                    <tbody id="analysisTableBody">
                        </tbody>
                </table>
            </div>

            <div class="p-4 bg-gray-50 border-t border-gray-200 flex justify-between items-center">
                <span id="paginationInfo" class="text-sm text-gray-600">Showing 1 to 10 of 0 entries</span>
                <div class="flex gap-2">
                    <button id="btnPrev" onclick="changePage(-1)" class="px-3 py-1 bg-white border border-gray-300 rounded text-sm font-medium hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed">Previous</button>
                    <button id="btnNext" onclick="changePage(1)" class="px-3 py-1 bg-white border border-gray-300 rounded text-sm font-medium hover:bg-gray-50 disabled:opacity-50 disabled:cursor-not-allowed">Next</button>
                </div>
            </div>
        </div>
    </div>

    <div id="screenshotModal" class="fixed inset-0 bg-slate-900/80 backdrop-blur-sm z-50 hidden flex justify-center items-center p-4 shadow-2xl" onclick="closeScreenshotModal()">
        <div class="relative max-w-5xl max-h-[90vh] bg-white rounded-xl overflow-hidden p-2" onclick="event.stopPropagation()">
            <button class="absolute top-4 right-4 bg-slate-800/80 hover:bg-slate-700 text-white rounded-full w-10 h-10 flex items-center justify-center font-bold text-xl transition-colors z-10 shadow" onclick="closeScreenshotModal()">&times;</button>
            <img id="modalImage" src="" class="max-w-full max-h-[85vh] object-contain rounded-lg" alt="Maximized view">
        </div>
    </div>

    <script>
        const reportData = ${reportDataJSON};

        let filteredPages = [...reportData.pages];
        let activeSeverityFilter = 'all';
        let searchQuery = '';

        let currentPage = 1;
        const itemsPerPage = 10;

        // Render the advanced checklist matrix state
        function getMatrixStatusHTML(title, issuesList, detailsContent = "") {
            const passed = !issuesList || issuesList.length === 0;
            return \`
                <div class="p-3 bg-white rounded-lg border \${passed ? 'border-green-100' : 'border-red-100'} shadow-sm">
                    <div class="flex items-center justify-between font-bold text-sm mb-1">
                        <span class="text-gray-700">\${title}</span>
                        <span>
                            \${passed ? 
                                '<span class="text-green-600"><i class="fa-solid fa-circle-check mr-1"></i>Passed</span>' : 
                                '<span class="text-red-500"><i class="fa-solid fa-circle-xmark mr-1"></i>Issues Found</span>'
                            }
                        </span>
                    </div>
                    \${!passed ? \`<div class="mt-2 text-xs text-gray-600 bg-slate-50 p-2 rounded max-h-32 overflow-y-auto">\${detailsContent || issuesList.map(i => typeof i === 'string' ? i : (i.message || i.issue || JSON.stringify(i))).join('<br/>')}</div>\` : ''}
                </div>
            \`;
        }

        function renderTable() {
            const tbody = document.getElementById("analysisTableBody");
            tbody.innerHTML = "";

            const totalItems = filteredPages.length;
            const totalPages = Math.ceil(totalItems / itemsPerPage) || 1;
            if (currentPage > totalPages) currentPage = totalPages;

            const start = (currentPage - 1) * itemsPerPage;
            const end = Math.min(start + itemsPerPage, totalItems);

            const pageItems = filteredPages.slice(start, end);

            if (pageItems.length === 0) {
                tbody.innerHTML = \`<tr><td colspan="5" class="p-8 text-center text-gray-500 italic">No matching URLs found.</td></tr>\`;
                document.getElementById("paginationInfo").textContent = "Showing 0 to 0 of 0 entries";
                document.getElementById("btnPrev").disabled = true;
                document.getElementById("btnNext").disabled = true;
                return;
            }

            pageItems.forEach((page, localIndex) => {
                const globalIndex = start + localIndex;
                const d = page.details || {};

                // Build Matrix Parameters Components
                const mixedContentHTML = getMatrixStatusHTML("Mixed Content", d.mixedContent);
                const accessibilityHTML = getMatrixStatusHTML("Accessibility", d.accessibilityIssues, d.accessibilityIssues ? d.accessibilityIssues.map(i => \`Tag: \${i.tag} | Type: \${i.type || 'N/A'} | Placeholder: \${i.placeholder || 'N/A'}\`).join('<br/>') : "");
                const h1HTML = getMatrixStatusHTML("Heading Architecture", d.h1Issues);
                const titleHTML = getMatrixStatusHTML("Page Title Audit", d.titleIssues);
                const brokenFormsHTML = getMatrixStatusHTML("Broken Forms Integrity", d.brokenForms, d.brokenForms ? d.brokenForms.map(f => \`Form index \${f.formIndex}: \${f.issues.join(', ')}\`).join('<br/>') : "");
                const brokenLinksHTML = getMatrixStatusHTML("Broken Links Status", d.brokenLinks, d.brokenLinks ? d.brokenLinks.map(l => \`URL: \${l.url} Status: \${l.status}\`).join('<br/>') : "");
                const brokenImagesHTML = getMatrixStatusHTML("Broken Images Checks", d.brokenImages);
                const jsErrorsHTML = getMatrixStatusHTML("JavaScript Engine", d.jsErrors, d.jsErrors ? d.jsErrors.map(e => \`\${e.message} \${e.stack || ''}\`).join('<br/>') : "");
                const consoleHTML = getMatrixStatusHTML("Dev Console Runtime", d.consoleErrors);
                const networkFailuresHTML = getMatrixStatusHTML("Failed Endpoints API", d.failedRequests, d.failedRequests ? d.failedRequests.map(r => \`Failed: \${r.url} - Error: \${r.error}\`).join('<br/>') : "");

                // Form findings validation errors block parsing
                let findingsHTML = '<div><p class="text-xs text-slate-400 italic">No finding structural errors</p></div>';
                if (d.findings && d.findings.length > 0) {
                    findingsHTML = \`
                        <div class="bg-white p-3 rounded shadow-sm border border-orange-100 max-h-64 overflow-y-auto">
                            \${d.findings.map(f => \`
                                <div class="mb-3 border-b border-gray-100 pb-2 last:mb-0 last:border-0 last:pb-0">
                                    <span class="inline-block bg-orange-100 text-orange-800 text-[10px] px-2 py-0.5 rounded font-bold uppercase mb-1">\${f.type}</span>
                                    \${f.error ? \`<p class="text-xs font-mono bg-red-50 p-1.5 rounded break-all text-red-700 mt-1">\${f.error.substring(0, 300)}\${f.error.length > 300 ? '...' : ''}</p>\` : ''}
                                    \${f.validationMessages ? f.validationMessages.map(vm => \`<p class="text-xs text-gray-700 font-medium mt-1">&#8226; \${vm.name || 'Field'}: \${vm.message}</p>\`).join('') : ''}
                                </div>
                            \`).join('')}
                        </div>
                    \`;
                }

                tbody.innerHTML += \`
                    <tr class="border-b hover:bg-gray-50 transition-colors">
                        <td class="p-4 max-w-xs truncate">
                            <span class="font-medium block text-slate-900 text-sm">\${page.title || 'Untitled Page'}</span>
                            <a href="\${page.url}" target="_blank" class="text-blue-500 text-xs hover:underline break-all"><i class="fa-solid fa-arrow-up-right-from-square mr-1 text-[10px]"></i>\${page.url}</a>
                        </td>
                        <td class="p-4 text-sm text-gray-600">\${page.loadTimeMs ? page.loadTimeMs + ' ms' : 'N/A'}</td>
                        <td class="p-4"><span class="bg-slate-200 text-slate-800 py-1 px-3 rounded-full text-xs font-bold">\${page.issuesCount || 0}</span></td>
                        <td class="p-4">
                            <span class="badge bg-\${page.severity || 'low'} uppercase">\${page.severity || 'N/A'}</span>
                        </td>
                        <td class="p-4 text-center">
                            <button onclick="toggleDetails(\${globalIndex})" class="bg-indigo-100 text-indigo-700 hover:bg-indigo-200 py-1 px-3 rounded text-sm transition-colors font-medium">
                                <i id="icon-\${globalIndex}" class="fa-solid fa-chevron-down mr-1"></i> View Audit
                            </button>
                        </td>
                    </tr>
                    <tr id="details-\${globalIndex}" class="details-row bg-slate-100 border-b">
                        <td colspan="5" class="p-6">
                            <div class="mb-4 bg-indigo-50 border-l-4 border-indigo-500 p-3 rounded-r-lg">
                                <h4 class="font-bold text-indigo-900 text-sm"><i class="fa-solid fa-square-poll-vertical mr-1"></i> Comprehensive Audit Verification Matrix Dashboard</h4>
                            </div>
                            <div class="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4 mb-6">
                                \${mixedContentHTML}
                                \${accessibilityHTML}
                                \${h1HTML}
                                \${titleHTML}
                                \${brokenFormsHTML}
                                \${brokenLinksHTML}
                                \${brokenImagesHTML}
                                \${jsErrorsHTML}
                                \${consoleHTML}
                                \${networkFailuresHTML}
                            </div>

                            <div class="grid grid-cols-1 lg:grid-cols-3 gap-6 border-t border-gray-300 pt-6 mt-2">
                                <div class="lg:col-span-2">
                                    <h4 class="font-bold text-orange-600 text-sm mb-2"><i class="fa-solid fa-bug mr-1"></i> Extended Assertions Engine Findings</h4>
                                    \${findingsHTML}
                                </div>
                                <div>
                                    <h4 class="font-bold text-gray-700 text-sm mb-2"><i class="fa-solid fa-image mr-1"></i> Visual Target Snapshot</h4>
                                    <div class="bg-white p-3 rounded border border-gray-200 flex flex-col items-center justify-center min-h-[150px]">
                                        \${page.screenshotPath || page.screenshot || page.screenshotUrl ? \`
                                            <img src="\${page.screenshotPath ? page.screenshotPath.split('/').pop() : (page.screenshot || page.screenshotUrl)}" class="max-h-40 rounded cursor-pointer border border-gray-200 shadow-sm hover:opacity-80 hover:scale-[1.01] transition-all" onclick="openScreenshotModal('\${page.screenshotPath ? page.screenshotPath.split('/').pop() : (page.screenshot || page.screenshotUrl)}')">
                                            <span class="text-[11px] text-slate-400 mt-2"><i class="fa-solid fa-magnifying-glass-plus mr-1"></i>Click to expand viewport</span>
                                        \` : \`
                                            <i class="fa-solid fa-image-notch text-slate-300 text-3xl mb-1"></i>
                                            <p class="text-xs text-gray-400">No screen buffer available</p>
                                        \`}
                                    </div>
                                </div>
                            </div>
                        </td>
                    </tr>
                \`;
            });

            // Update footer controls
            document.getElementById("paginationInfo").textContent = \`Showing \${start + 1} to \${end} of \${totalItems} entries\`;
            document.getElementById("btnPrev").disabled = (currentPage === 1);
            document.getElementById("btnNext").disabled = (currentPage === totalPages);
        }

        function toggleDetails(index) {
            const row = document.getElementById('details-' + index);
            const icon = document.getElementById('icon-' + index);
            row.classList.toggle('active');
            if(row.classList.contains('active')) {
                icon.classList.replace('fa-chevron-down', 'fa-chevron-up');
            } else {
                icon.classList.replace('fa-chevron-up', 'fa-chevron-down');
            }
        }

        function changePage(direction) {
            currentPage += direction;
            renderTable();
        }

        function handleSearch() {
            searchQuery = document.getElementById("tableSearch").value.toLowerCase();
            applyFilters();
        }

        function filterBySeverity(severity) {
            activeSeverityFilter = severity;

            // Highlight visual effect
            ['all', 'critical', 'high', 'medium', 'low'].forEach(s => {
                const el = document.getElementById('card-' + s);
                if(s === severity) {
                    el.classList.add('ring-2', 'ring-indigo-600', 'bg-indigo-50/50');
                } else {
                    el.classList.remove('ring-2', 'ring-indigo-600', 'bg-indigo-50/50');
                }
            });

            const badge = document.getElementById("activeFilterBadge");
            if(severity !== 'all') {
                badge.textContent = "Filtered to: " + severity.toUpperCase();
                badge.classList.remove('hidden');
            } else {
                badge.classList.add('hidden');
            }

            applyFilters();
        }

        function applyFilters() {
            filteredPages = reportData.pages.filter(page => {
                const matchesSeverity = (activeSeverityFilter === 'all' || page.severity === activeSeverityFilter);
                const targetText = \`\${page.title || ''} \${page.url || ''}\`.toLowerCase();
                const matchesSearch = targetText.includes(searchQuery);
                return matchesSeverity && matchesSearch;
            });
            currentPage = 1;
            renderTable();
        }

        let sortDirections = {};
        function sortTable(colIndex, type) {
            sortDirections[colIndex] = !sortDirections[colIndex];
            const isAsc = sortDirections[colIndex];

            filteredPages.sort((a, b) => {
                let cellA = colIndex === 0 ? (a.title || '') : colIndex === 1 ? (a.loadTimeMs || 0) : colIndex === 2 ? (a.issuesCount || 0) : (a.severity || '');
                let cellB = colIndex === 0 ? (b.title || '') : colIndex === 1 ? (b.loadTimeMs || 0) : colIndex === 2 ? (b.issuesCount || 0) : (b.severity || '');

                if (type === 'number') {
                    return isAsc ? cellA - cellB : cellB - cellA;
                } else if (type === 'severity') {
                    const weights = { critical: 4, high: 3, medium: 2, low: 1 };
                    let wA = weights[String(cellA).toLowerCase()] || 0;
                    let wB = weights[String(cellB).toLowerCase()] || 0;
                    return isAsc ? wA - wB : wB - wA;
                } else {
                    return isAsc ? String(cellA).localeCompare(String(cellB)) : String(cellB).localeCompare(String(cellA));
                }
            });
            renderTable();
        }

        function openScreenshotModal(src) {
            document.getElementById('modalImage').src = src;
            document.getElementById('screenshotModal').classList.remove('hidden');
        }
        function closeScreenshotModal() {
            document.getElementById('screenshotModal').classList.add('hidden');
        }

        window.addEventListener('DOMContentLoaded', () => {
            renderTable();

            const pieCtx = document.getElementById('severityPieChart').getContext('2d');
            new Chart(pieCtx, {
                type: 'doughnut',
                data: {
                    labels: ['Critical', 'High', 'Medium', 'Low'],
                    datasets: [{
                        data: [
                            reportData.scanSummary.critical || 0, 
                            reportData.scanSummary.high || 0, 
                            reportData.scanSummary.medium || 0, 
                            reportData.scanSummary.low || 0
                        ],
                        backgroundColor: ['#ef4444', '#f97316', '#eab308', '#3b82f6'],
                        borderWidth: 0
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { position: 'bottom' } },
                    cutout: '70%'
                }
            });

            const sortedPages = [...reportData.pages].sort((a, b) => (b.issuesCount || 0) - (a.issuesCount || 0)).slice(0, 10);
            const barLabels = sortedPages.map(p => {
                const urlParts = p.url ? p.url.replace(/\\/$/, '').split('/') : ['Unknown'];
                return urlParts[urlParts.length - 1] || 'Home';
            });
            const barData = sortedPages.map(p => p.issuesCount || 0);

            const barCtx = document.getElementById('issuesBarChart').getContext('2d');
            new Chart(barCtx, {
                type: 'bar',
                data: {
                    labels: barLabels,
                    datasets: [{
                        label: 'Issue Count',
                        data: barData,
                        backgroundColor: '#6366f1',
                        borderRadius: 4
                    }]
                },
                options: {
                    responsive: true,
                    maintainAspectRatio: false,
                    plugins: { legend: { display: false } },
                    scales: {
                        y: { beginAtZero: true, ticks: { stepSize: 1 } },
                        x: { ticks: { maxRotation: 45, minRotation: 45 } }
                    }
                }
            });
        });
    </script>
</body>
</html>
